parameters.jsCode:
let msg = "Executions:\n\n"
if ($input.first().json.id === null) {
  return {
    json: {
      msg: "No executions."
    }
  }
}
for (const item of $input.all()) {
  let status = item.json.finished ? '✅' : '❌'
  let mode = item.json.mode === 'manual' ? ' (manual)' : ''
  msg = msg + (status + " " + item.json.workflow + " - " + item.json.id + " - " + item.json.started + mode + "\n")
}
return {
  json: {
    msg: msg
  }
}

const items = $input.all();
let msg = "Workflows:\n\n";
const workflows = [];
if (items.length === 0 || items[0].json.name === null) {
  return { json: { retorno: "No workflows.", workflows: [] } };
}
for (const item of items) {
  const name = item.json.name || '';
  const active = !!item.json.active;
  workflows.push({ name, active });
  msg = msg + (active ? '🟢' : '⚫') + "  " + name + "\n";
}
return { json: { retorno: msg, workflows } };

let msg = "Archived Workflows Deleted:\n\n"
if ($('Archived List').first().json.name === null) {
  return {
    json: {
      msg: "No archived workflows."
    }
  }
}
for (const item of $('Archived List').all()) {
  msg = msg + ("🗑" + "  " + item.json.name + "\n")
}
return {
  json: {
    msg: msg
  }
}

